from pathlib import Path

a512 = int("20683933304168370455845888199423184913065902865418847777579583388107446748984301367057531643348161366707210878327722623156679249082293555084675232652653720")
b512 = int("73308878442923045059976294952255587999123263358420094990610382528634504583670384642226159738983164471491540131922673939258587560940691215067502770621913422")

a1024 = int("")
b1024 = int("")

a2048 = int("")
b2048 = int("")


def trunc_div_mod(a: int, b: int):
    if b == 0:
        raise ZeroDivisionError
    q = abs(a) // abs(b)
    if (a < 0) ^ (b < 0):
        q = -q
    r = a - q * b
    return q, r

lines = []

# 512-bit set
lines.append(str(a512 + b512))
lines.append(str(a512 - b512))
lines.append(str(b512 - a512))
lines.append(str(a512 * b512))
q, r = trunc_div_mod(a512, b512)
lines.append(str(q))
lines.append(str(r))
q, r = trunc_div_mod(b512, a512)
lines.append(str(q))
lines.append(str(r))
q, r = trunc_div_mod(-a512, b512)
lines.append(str(q))
lines.append(str(r))
q, r = trunc_div_mod(a512, -b512)
lines.append(str(q))
lines.append(str(r))
lines.append(str((-a512) * b512))
lines.append(str((-a512) + b512))
lines.append(str(a512 + (-b512)))

# 1024-bit set
lines.append(str(a1024 + b1024))
lines.append(str(a1024 - b1024))
lines.append(str(b1024 - a1024))
lines.append(str(a1024 * b1024))
q, r = trunc_div_mod(a1024, b1024)
lines.append(str(q))
lines.append(str(r))
q, r = trunc_div_mod(-a1024, b1024)
lines.append(str(q))
lines.append(str(r))
q, r = trunc_div_mod(a1024, -b1024)
lines.append(str(q))
lines.append(str(r))
lines.append(str((-a1024) * b1024))

# 2048-bit add/sub
lines.append(str(a2048 + b2048))
lines.append(str(a2048 - b2048))
lines.append(str(b2048 - a2048))

# mixed-size (512/1024)
lines.append(str(a512 + a1024))
lines.append(str(a1024 - a512))
lines.append(str(a512 - a1024))
lines.append(str(a512 * a1024))
q, r = trunc_div_mod(a1024, a512)
lines.append(str(q))
lines.append(str(r))
q, r = trunc_div_mod(a512, a1024)
lines.append(str(q))
lines.append(str(r))

# mixed-size (512/2048)
lines.append(str(a512 + a2048))
lines.append(str(a2048 - a512))
lines.append(str(a512 - a2048))
lines.append(str(a512 * a2048))
q, r = trunc_div_mod(a2048, a512)
lines.append(str(q))
lines.append(str(r))
q, r = trunc_div_mod(a512, a2048)
lines.append(str(q))
lines.append(str(r))

# mixed-size (1024/2048)
lines.append(str(a1024 + a2048))
lines.append(str(a2048 - a1024))
lines.append(str(a1024 - a2048))
lines.append(str(a1024 * a2048))
q, r = trunc_div_mod(a2048, a1024)
lines.append(str(q))
lines.append(str(r))
q, r = trunc_div_mod(a1024, a2048)
lines.append(str(q))
lines.append(str(r))

expected = "\n".join(lines) + "\n"

tblo_source = f"""func main(): void {{
    var a512: bigint = {a512}n;
    var b512: bigint = {b512}n;
    var a1024: bigint = {a1024}n;
    var b1024: bigint = {b1024}n;
    var a2048: bigint = {a2048}n;
    var b2048: bigint = {b2048}n;

    println(a512 + b512);
    println(a512 - b512);
    println(b512 - a512);
    println(a512 * b512);
    println(a512 / b512);
    println(a512 % b512);
    println(b512 / a512);
    println(b512 % a512);
    println(-a512 / b512);
    println(-a512 % b512);
    println(a512 / -b512);
    println(a512 % -b512);
    println(-a512 * b512);
    println(-a512 + b512);
    println(a512 + -b512);

    println(a1024 + b1024);
    println(a1024 - b1024);
    println(b1024 - a1024);
    println(a1024 * b1024);
    println(a1024 / b1024);
    println(a1024 % b1024);
    println(-a1024 / b1024);
    println(-a1024 % b1024);
    println(a1024 / -b1024);
    println(a1024 % -b1024);
    println(-a1024 * b1024);

    println(a2048 + b2048);
    println(a2048 - b2048);
    println(b2048 - a2048);

    println(a512 + a1024);
    println(a1024 - a512);
    println(a512 - a1024);
    println(a512 * a1024);
    println(a1024 / a512);
    println(a1024 % a512);
    println(a512 / a1024);
    println(a512 % a1024);

    println(a512 + a2048);
    println(a2048 - a512);
    println(a512 - a2048);
    println(a512 * a2048);
    println(a2048 / a512);
    println(a2048 % a512);
    println(a512 / a2048);
    println(a512 % a2048);

    println(a1024 + a2048);
    println(a2048 - a1024);
    println(a1024 - a2048);
    println(a1024 * a2048);
    println(a2048 / a1024);
    println(a2048 % a1024);
    println(a1024 / a2048);
    println(a1024 % a2048);
}}
"""

Path("tests/native_integration_tests/bigint_large_tests.tblo").write_text(tblo_source, encoding="ascii")
Path("tests/native_integration_tests/expected_output/bigint_large_tests.expected").write_text(expected, encoding="ascii")
print("wrote bigint_large_tests")
